'use client'
import { cn, createMachine, useMachine, useSignal, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { InputHTMLAttributes, KeyboardEvent } from 'react'
import styles from './number-input.module.css'

const machine = createMachine({
  initial: 'idle' as const,
  states: {
    idle: { on: { FOCUS: 'focused' } },
    focused: { on: { BLUR: 'idle' } },
  },
})

export interface NumberInputProps extends Omit<
  InputHTMLAttributes<HTMLInputElement>,
  'size' | 'type' | 'value' | 'defaultValue' | 'onChange' | 'min' | 'max' | 'step'
> {
  value?: number | null
  defaultValue?: number
  onChange?: (value: number | null) => void
  min?: number
  max?: number
  step?: number
  precision?: number
  formatOptions?: Intl.NumberFormatOptions
  label?: string
  hint?: string
  error?: string
  size?: 'sm' | 'md' | 'lg'
  incrementLabel?: string
  decrementLabel?: string
}

function clamp(value: number, min?: number, max?: number): number {
  let result = value
  if (min !== undefined) result = Math.max(result, min)
  if (max !== undefined) result = Math.min(result, max)
  return result
}

function decimalsOf(value: number): number {
  const text = String(value)
  const dot = text.indexOf('.')
  return dot === -1 ? 0 : text.length - dot - 1
}

function roundTo(value: number, decimals: number): number {
  const factor = 10 ** decimals
  return Math.round(value * factor) / factor
}

function parseText(text: string): number | null {
  const trimmed = text.trim()
  if (trimmed === '') return null
  const parsed = Number(trimmed)
  return Number.isFinite(parsed) ? parsed : null
}

export function NumberInput({
  value,
  defaultValue,
  onChange,
  min,
  max,
  step = 1,
  precision,
  formatOptions,
  label,
  hint,
  error,
  size = 'md',
  disabled,
  incrementLabel,
  decrementLabel,
  className,
  id,
  onFocus,
  onBlur,
  onKeyDown,
  ...props
}: NumberInputProps) {
  useSignals()
  const resolvedIncrementLabel = incrementLabel ?? t(builtin.numberInput.increment)
  const resolvedDecrementLabel = decrementLabel ?? t(builtin.numberInput.decrement)
  const [state, send] = useMachine(machine)
  const isControlled = value !== undefined
  const committed = useSignal<number | null>(defaultValue ?? null)
  const text = useSignal('')

  const current = isControlled ? value : committed.value
  const inputId =
    id ?? (label ? `cascade-number-input-${label.toLowerCase().replace(/\s+/g, '-')}` : undefined)

  const setValue = (next: number | null) => {
    if (!isControlled) committed.value = next
    text.value = next == null ? '' : String(next)
    if (next !== current) onChange?.(next)
  }

  const commitText = () => {
    let next = parseText(text.value)
    if (next != null) {
      next = clamp(next, min, max)
      if (precision !== undefined) next = roundTo(next, precision)
    }
    setValue(next)
  }

  const stepBy = (direction: 1 | -1) => {
    const base = (state.value === 'focused' ? parseText(text.value) : current) ?? 0
    const decimals = precision ?? Math.max(decimalsOf(step), decimalsOf(base))
    setValue(clamp(roundTo(base + direction * step, decimals), min, max))
  }

  const format = (next: number | null): string => {
    if (next == null) return ''
    return formatOptions
      ? new Intl.NumberFormat(undefined, formatOptions).format(next)
      : String(next)
  }

  const display = state.value === 'focused' ? text.value : format(current)
  const atMax = current != null && max !== undefined && current >= max
  const atMin = current != null && min !== undefined && current <= min

  const handleKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'ArrowUp') {
      event.preventDefault()
      stepBy(1)
    } else if (event.key === 'ArrowDown') {
      event.preventDefault()
      stepBy(-1)
    } else if (event.key === 'Enter') {
      commitText()
    }
    onKeyDown?.(event)
  }

  return (
    <div
      className={cn(styles['wrapper'], className)}
      data-state={error ? 'error' : state.value}
      data-size={size}
    >
      {label && (
        <label className={styles['label']} htmlFor={inputId}>
          {label}
        </label>
      )}
      <div className={styles['field']}>
        <input
          id={inputId}
          type="text"
          inputMode="decimal"
          autoComplete="off"
          role="spinbutton"
          className={styles['input']}
          value={display}
          disabled={disabled}
          aria-valuenow={current ?? undefined}
          aria-valuemin={min}
          aria-valuemax={max}
          aria-invalid={error ? true : undefined}
          aria-describedby={error ? `${inputId}-error` : hint ? `${inputId}-hint` : undefined}
          onChange={(e) => {
            text.value = e.target.value
          }}
          onFocus={(e) => {
            text.value = current == null ? '' : String(current)
            send('FOCUS')
            onFocus?.(e)
          }}
          onBlur={(e) => {
            commitText()
            send('BLUR')
            onBlur?.(e)
          }}
          onKeyDown={handleKeyDown}
          {...props}
        />
        <div className={styles['steppers']}>
          <button
            type="button"
            className={styles['stepper']}
            aria-label={resolvedIncrementLabel}
            tabIndex={-1}
            disabled={disabled || atMax}
            onMouseDown={(e) => e.preventDefault()}
            onClick={() => stepBy(1)}
          >
            <svg viewBox="0 0 10 10" aria-hidden="true" focusable="false">
              <path
                d="M2 6.5 5 3.5 8 6.5"
                fill="none"
                stroke="currentColor"
                strokeWidth="1.5"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </button>
          <button
            type="button"
            className={styles['stepper']}
            aria-label={resolvedDecrementLabel}
            tabIndex={-1}
            disabled={disabled || atMin}
            onMouseDown={(e) => e.preventDefault()}
            onClick={() => stepBy(-1)}
          >
            <svg viewBox="0 0 10 10" aria-hidden="true" focusable="false">
              <path
                d="M2 3.5 5 6.5 8 3.5"
                fill="none"
                stroke="currentColor"
                strokeWidth="1.5"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </button>
        </div>
      </div>
      {error && (
        <span id={`${inputId}-error`} className={styles['error']} role="alert">
          {error}
        </span>
      )}
      {!error && hint && (
        <span id={`${inputId}-hint`} className={styles['hint']}>
          {hint}
        </span>
      )}
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);
    --_stepper-width: 1.5rem;

    &[data-size='sm'] {
      --_input-height: 2rem;
      --_input-font: var(--cascivo-text-sm);
      --_input-px: var(--cascivo-space-3);
    }

    &[data-size='md'] {
      --_input-height: 2.5rem;
      --_input-font: var(--cascivo-text-sm);
      --_input-px: var(--cascivo-space-4);
    }

    &[data-size='lg'] {
      --_input-height: 3rem;
      --_input-font: var(--cascivo-text-base);
      --_input-px: var(--cascivo-space-4);
    }
  }

  .label {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-snug);
  }

  .field {
    position: relative;
  }

  .input {
    width: 100%;
    height: var(--_input-height, 2.5rem);
    padding-inline-start: var(--_input-px, var(--cascivo-space-4));
    padding-inline-end: calc(var(--_stepper-width) + var(--cascivo-space-2));
    font-family: var(--cascivo-font-sans);
    font-size: var(--_input-font, var(--cascivo-text-sm));
    font-variant-numeric: tabular-nums;
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);
    outline: none;

    &::placeholder {
      color: var(--cascivo-color-text-muted);
    }

    &:hover:not(:disabled):not(:focus) {
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus {
      border-color: var(--cascivo-color-accent);
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
      background-color: var(--cascivo-color-bg-subtle);
    }

    .wrapper[data-state='error'] & {
      border-color: var(--cascivo-color-destructive);

      &:focus {
        box-shadow: 0 0 0 3px rgb(from var(--cascivo-color-destructive) r g b / 0.3);
      }
    }
  }

  .steppers {
    position: absolute;
    inset-block: 1px;
    inset-inline-end: 1px;
    display: flex;
    flex-direction: column;
    inline-size: var(--_stepper-width);
    border-start-end-radius: calc(var(--cascivo-radius-field) - 1px);
    border-end-end-radius: calc(var(--cascivo-radius-field) - 1px);
    overflow: hidden;
  }

  .stepper {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    border: none;
    border-inline-start: 1px solid var(--cascivo-color-border);
    background-color: transparent;
    color: var(--cascivo-color-text-subtle);
    cursor: pointer;
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out);

    & + & {
      border-block-start: 1px solid var(--cascivo-color-border);
    }

    &:hover:not(:disabled) {
      background-color: var(--cascivo-color-bg-subtle);
      color: var(--cascivo-color-text);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }

    & svg {
      inline-size: 0.625rem;
      block-size: 0.625rem;
    }
  }

  .error {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-destructive);
    line-height: var(--cascivo-leading-snug);
  }

  .hint {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-snug);
  }
}
